// Generate slug from card details
function makeSlug(player, year, set, cardNumber) {
  const setShort = set.replace(/\d{4}(-\d{2})?\s+/g, '').replace(/[^a-zA-Z0-9\s]/g, '').trim().toLowerCase().replace(/\s+/g, '-');
  const playerSlug = player.toLowerCase().replace(/[^a-zA-Z0-9\s]/g, '').trim().replace(/\s+/g, '-');
  const num = cardNumber.replace('#', '').replace(/\//g, '-').toLowerCase();
  return `${year}-${setShort}-${playerSlug}-${num}`;
}

// Generate eBay search URL
function makeEbayUrl(player, year, set, cardNumber) {
  const terms = `${year} ${set.replace(/\d{4}(-\d{2})?\s+/, '')} ${player} ${cardNumber}`.replace(/[#]/g, '').replace(/\s+/g, '+');
  return `https://www.ebay.com/sch/i.html?_nkw=${encodeURIComponent(terms).replace(/%2B/g, '+')}`;
}

function sportImage(sport) {
  return `/images/placeholder-${sport}.svg`;
}

const output = cards.map(c => {
  const [player, year, set, sport, cardNumber, valueRaw, valueGem, description, rookie] = c;
  // Ensure set name includes the year (matching existing data format)
  const fullSet = set.match(/^\d{4}/) ? set : `${year} ${set}`;
  const slug = makeSlug(player, year, fullSet, cardNumber);
  return `  { slug: '${slug}', name: '${fullSet} ${player} #${cardNumber}', year: ${year}, set: '${fullSet}', sport: '${sport}', player: '${player}', cardNumber: '${cardNumber}', estimatedValueRaw: '${valueRaw}', estimatedValueGem: '${valueGem}', imageUrl: '${sportImage(sport)}', ebaySearchUrl: '${makeEbayUrl(player, year, fullSet, cardNumber)}', description: '${description.replace(/'/g, "\\'")}', rookie: ${rookie} },`;
});

console.log(output.join('\n'));
process.stderr.write(`\nGenerated ${output.length} cards\n`);
